"""Chapter 5: Structural analysis EN 1993-1-1:2013."""

import typing as t

from fhecor_structuralcodes.EN1993_1_5_2006.chapter_4_plate_buckling_direct_stress import k_sigma_table_4_2


def epsilon(fy: float) -> float:
    """Computes the coefficient epsilon based on the yield strength fy.

    EUROCODE 3: UNE-EN 1993-1-1:2013, Table 5.2 (sheet 1 of 3).

    Args:
        fy (float): Yield strength of the structural steel in MPa (N/mm2).

    Returns:
        float: The value of the epsilon coefficient.
    """
    return (235 / fy) ** 0.5


def internal_plate_plastic_class(c: float, t: float, fy: float, alpha: float) -> t.Literal[1, 2, 3]:
    """Classifies an internal compression plate element for plastic behavior (Class 1 or 2, 3).

    This function focuses on the flexo-compression case, which encompasses
    both pure bending and pure compression through the stress ratio psi.

    EUROCODE 3: UNE-EN 1993-1-1:2013, Table 5.2 (sheet 1 of 3).

    Args:
        c (float): Internal width of the plate in mm.
        t (float): Thickness of the plate in mm.
        fy (float): Yield strength of the steel in MPa (N/mm2).
        alpha: Portion of the element in compression (typically based on PNA).

    Returns: 1, 2, or 3 (3 means it exceeds Class 2 limits).
    """
    eps = epsilon(fy)
    ratio = c / t

    # Class 1 limits
    lim1 = (396 * eps) / (13 * alpha - 1) if alpha > 0.5 else (36 * eps) / alpha
    if ratio <= lim1:
        return 1

    # Class 2 limits
    lim2 = (456 * eps) / (13 * alpha - 1) if alpha > 0.5 else (41.5 * eps) / alpha
    if ratio <= lim2:
        return 2

    return 3


def internal_plate_elastic_class(c: float, t: float, fy: float, psi: float) -> t.Literal[3, 4]:
    """Classifies an internal plate for elastic behavior (Class 3 or 4).

    Args:
        c (float): Internal width of the plate in mm.
        t (float): Thickness of the plate in mm.
        fy (float): Yield strength of the steel in MPa (N/mm2).
        psi (float): Stress ratio (sigma2 / sigma1). sigma1 is the maximum
            compression stress (positive) and sigma2 is the stress at the
            opposite end of the element.
            psi = 1 for uniform compression.
            psi = -1 for pure bending.

    Returns: 3 or 4 (4 means it exceeds Class 3 limits).
    """
    eps = epsilon(fy)
    ratio = c / t

    lim3 = 42 * eps / (0.67 + 0.33 * psi) if psi > -1 else 62 * eps * (1 - psi) * (abs(psi) ** 0.5)

    return 3 if ratio <= lim3 else 4


def outstand_flange_plastic_class(
    c: float, t: float, fy: float, alpha: float, section_type: t.Literal['rolled', 'welded'] = 'rolled'
) -> t.Literal[1, 2, 3]:
    """Classifies an outstand compression plate element for plastic behavior (e.g., a flange).

    EUROCODE 3: UNE-EN 1993-1-1:2013, Table 5.2 (sheet 2 of 3).

    Args:
        c (float): Outstand width of the flange in mm.
        t (float): Thickness of the flange in mm.
        fy (float): Yield strength of the steel in MPa (N/mm2).
        alpha: Portion of the element in compression (typically based on PNA).
        section_type (str): Type of section, 'rolled' or 'welded'.

    Returns:
        int: The cross-section class (1, 2, 3).

    Raises:
        ValueError: If dimensions or fy are invalid.
    """
    eps = epsilon(fy)
    ratio = c / t
    _type = section_type.lower().strip()

    # Alpha factor adjustment for welded sections (Table 5.2 sheet 2)
    factor = alpha * (alpha**0.5) if _type == 'welded' else alpha

    if ratio <= 9 * eps / factor:
        return 1
    if ratio <= 10 * eps / factor:
        return 2
    return 3


def outstand_flange_elastic_class(
    c: float, t: float, fy: float, psi: float, max_stress_at_supported_edge: bool
) -> t.Literal[3, 4]:
    """Classifies an outstand compression plate element for elastic behavior (e.g., a flange).

    EUROCODE 3: UNE-EN 1993-1-1:2013, Table 5.2 (sheet 2 of 3).

    Args:
        c (float): Outstand width of the flange in mm.
        t (float): Thickness of the flange in mm.
        fy (float): Yield strength of the steel in MPa (N/mm2).
        psi (float): Stress ratio (sigma2 / sigma1).
            psi = 1 for uniform compression.
            psi = -1 for pure bending.
        section_type (str): Type of section, 'rolled' or 'welded'.

    Returns:
        int: The cross-section class (3 or 4).

    Raises:
        ValueError: If dimensions or fy are invalid.
    """
    eps = epsilon(fy)
    ratio = c / t

    # k_sigma depends on the stress distribution (EN 1993-1-5)
    if psi == 1.0:  # Uniform compression
        lim3 = 14 * eps
    else:
        # Approximate k_sigma logic for outstands
        k_sigma = k_sigma_table_4_2(psi, max_stress_at_supported_edge)
        lim3 = 21 * eps * (k_sigma**0.5)

    return 3 if ratio <= lim3 else 4


def angle_class(h: float, b: float, t: float, fy: float) -> int:
    """Classifies an angle section in compression.

    EUROCODE 3: UNE-EN 1993-1-1:2013, Table 5.2 (sheet 3 of 3).
    Note: Does not apply to angles in continuous contact with other components.

    Args:
        h (float): Larger leg length in mm.
        b (float): Smaller leg length in mm.
        t (float): Thickness of the angle in mm.
        fy (float): Yield strength of the steel in MPa (N/mm2).

    Returns:
        int: The cross-section class (1, 2, 3, or 4).
    """
    if h <= 0 or b <= 0 or t <= 0 or fy <= 0:
        raise ValueError('Dimensions and fy must be greater than 0.')

    eps = epsilon(fy)

    # Class 1 and 2: Referred to 'outstand flanges' analogously
    # Using psi=1 (compression) and section_type='rolled' as default
    if h / t <= 9 * eps:
        return 1
    if h / t <= 10 * eps:
        return 2

    # Class 3: Specific dual limit for angles
    if (h / t <= 15 * eps) and ((h + b) / (2 * t) <= 11.5 * eps):
        return 3

    return 4


def chs_class(d: float, t: float, fy: float) -> int:
    """Classifies a circular hollow section (CHS) under bending and/or compression.

    EUROCODE 3: UNE-EN 1993-1-1:2013, Table 5.2 (sheet 3 of 3).

    Args:
        d (float): External diameter of the section in mm.
        t (float): Thickness of the wall in mm.
        fy (float): Yield strength of the steel in MPa (N/mm2).

    Returns:
        int: The cross-section class (1, 2, 3, or 4).
    """
    if d <= 0 or t <= 0 or fy <= 0:
        raise ValueError('Dimensions and fy must be greater than 0.')

    eps_sq = epsilon(fy) ** 2
    ratio = d / t

    if ratio <= 50 * eps_sq:
        return 1
    if ratio <= 70 * eps_sq:
        return 2
    if ratio <= 90 * eps_sq:
        return 3

    return 4
